import axios from 'axios'

const request = axios.create({
    baseURL: 'http://localhost:9090',  // 后端基础地址
    timeout: 5000
})

// request 拦截器：请求发送前处理
request.interceptors.request.use(config => {
    config.headers['Content-Type'] = 'application/json;charset=utf-8';
    // 调试用：打印请求的URL和方法
    console.log(`[请求] ${config.method.toUpperCase()} ${config.baseURL}${config.url}`);
    // config.headers['token'] = user.token;  // 如有token可开启
    return config
}, error => {
    return Promise.reject(error)
});

// response 拦截器：接口响应后处理
request.interceptors.response.use(
    response => {
        let res = response.data;
        // 处理文件类型响应
        if (response.config.responseType === 'blob') {
            return res
        }
        // 兼容字符串格式的响应数据
        if (typeof res === 'string') {
            res = res ? JSON.parse(res) : res
        }
        return res;
    },
    error => {
        console.log('err' + error) // 保留原有打印

        // 重点：解析500错误的详细信息
        if (error.response) {
            const { status, config, data } = error.response;
            // 针对500错误的特殊处理
            if (status === 500) {
                console.error(`=== 500错误详情 ===`);
                console.error(`请求地址：${config.baseURL}${config.url}`);
                console.error(`请求方法：${config.method.toUpperCase()}`);
                console.error(`后端返回：`, data); // 打印后端返回的具体错误原因
                // 给用户友好提示（可替换为项目的提示组件，如ElementUI的Message）
                alert(`接口请求失败（500）：${config.url}\n请检查后端服务或联系开发人员`);
            }
        } else if (error.request) {
            // 请求发出去了但没收到响应（如后端服务未启动）
            console.error('请求无响应：后端服务可能未启动或端口错误');
            alert('请求失败：无法连接到后端服务器，请检查服务是否启动');
        }

        // 返回错误，让业务代码可以继续处理
        return Promise.reject(error)
    }
)

export default request
